python3 -c "
import ast
F = '/home/azureuser/aixa-responder.py'
with open(F) as fh: src = fh.read()
tree = ast.parse(src)
lines = src.splitlines()
print('===== FUNCTION DEFS containing post_reply or redact =====')
for node in ast.walk(tree):
    if isinstance(node, ast.FunctionDef):
        if 'post_reply' in node.name or 'redact' in node.name:
            print(f'  L{node.lineno}: def {node.name}({\",\".join(a.arg for a in node.args.args)}) ')
print()
print('===== ASSIGNMENTS to post_reply* =====')
for node in ast.walk(tree):
    if isinstance(node, ast.Assign):
        for t in node.targets:
            if isinstance(t, ast.Name) and 'post_reply' in t.id:
                print(f'  L{node.lineno}: {t.id} = ...   src=> {lines[node.lineno-1].strip()}')
print()
print('===== ALL CALLS to post_reply* =====')
for node in ast.walk(tree):
    if isinstance(node, ast.Call):
        f = node.func
        n = None
        if isinstance(f, ast.Name): n = f.id
        elif isinstance(f, ast.Attribute): n = f.attr
        if n and 'post_reply' in n:
            print(f'  L{node.lineno}: calls {n}()   src=> {lines[node.lineno-1].strip()[:120]}')
"
